const dbItem = $('PGSQL - List Available Products').first().json || {};
const req = $('Webhook - List Products').first().json;

function asArray(v) {
  if (v == null) return [];
  return Array.isArray(v) ? v : [v];
}

function parseRecords(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === 'string' && v.trim()) {
    const parsed = JSON.parse(v);
    return Array.isArray(parsed) ? parsed : [];
  }
  return [];
}

let products = parseRecords(dbItem.records);

// Some n8n/Postgres configurations emit direct SELECT rows instead of a single records field.
if (!products.length && dbItem.records == null) {
  const directRows = $('PGSQL - List Available Products').all().map(i => i.json || {});
  const successOnly = directRows.length === 1 && directRows[0].success === true && Object.keys(directRows[0]).length === 1;
  if (successOnly) {
    throw new Error('PGSQL product list returned only success=true. The Postgres node did not return SELECT rows; re-import this corrected workflow and confirm the node query is the SELECT json_agg query.');
  }
  products = directRows.filter(r => r.mushroomprocess_product_id || r.airtable_record_id);
}

function parseAllowedLocations(req) {
  const q = req?.query || {};

  if (q.storage_locations_json) {
    try {
      const parsed = JSON.parse(q.storage_locations_json);
      return asArray(parsed).map(x => String(x).trim()).filter(Boolean);
    } catch (e) {
      // Fall through to legacy handling.
    }
  }

  if (q.storage_locations) {
    return String(q.storage_locations)
      .split(',')
      .map(x => x.trim())
      .filter(Boolean);
  }

  if (q.storage_location) {
    return [String(q.storage_location).trim()].filter(Boolean);
  }

  return [];
}

const allowedLocations = parseAllowedLocations(req);
const allowedLocationSet = new Set(allowedLocations.map(x => x.toLowerCase()));
const excludeLocations = new Set(['shipped', 'consumed', 'expired']);
const out = [];

for (const p of products) {
  const product_id = p.mushroomprocess_product_id;
  if (!product_id) continue;

  const locNames = asArray(p.storage_locations)
    .map(x => String(x || '').trim())
    .filter(Boolean);

  if (locNames.some(n => excludeLocations.has(n.toLowerCase()))) continue;

  if (
    allowedLocationSet.size > 0 &&
    !locNames.some(n => allowedLocationSet.has(String(n).trim().toLowerCase()))
  ) {
    continue;
  }

  out.push({
    airtable_record_id: p.airtable_record_id,
    mushroomprocess_product_id: product_id,
    item_name: p.item_name ?? null,
    strain: p.strain ?? null,
    net_weight_g: p.net_weight_g ?? null,
    unit: p.unit || 'g',
    storage_location: locNames[0] ?? null,
    storage_locations: locNames,
  });
}

return [{
  json: {
    ok: true,
    data: out,
    count: out.length,
    filter: {
      storage_locations: allowedLocations
    }
  }
}];
